mapper.select:
SELECT  FROM orders o
    INNER JOIN `user` u ON u.id=o.user_id LEFT JOIN order_item oi ON oi.order_id=o.id WHERE o.user_id=#{userId}
    AND o.order_type=#{orderType}AND o.status=#{status}
    GROUP BY o.id,o.order_no,o.order_type,o.status,u.nickname,o.contact_name,o.table_no,o.address_area,
      o.address_detail,o.address_house_number,o.pay_amount,o.create_time ORDER BY o.create_time DESC,o.id DESC
